sql:
SELECT official_id
FROM officials
WHERE gender = 'Male';

SELECT officials.legal_name, party_affiliations.position_title
FROM officials
JOIN party_affiliations ON officials.official_id = party_affiliations.official_id;

SELECT AVG(
    strftime('%Y', 'now') - strftime('%Y', date_of_birth) 
    - (strftime('%m-%d', 'now') < strftime('%m-%d', date_of_birth))
) AS average_age
FROM officials;

SELECT DISTINCT officials.legal_name
FROM officials
INNER JOIN committee_members ON officials.official_id = committee_members.official_id;

SELECT legal_name, gender
FROM officials
WHERE official_id = 100;

external_knowledge:
- "youngest blooming bud" refers to the senator with the most recent date of birth;
- "oldest withering leaf" refers to the senator with the earliest date of birth;
- The "garden of representatives" is a metaphorical reference to the collection of senators.

sql:
SELECT DISTINCT title
FROM officials
ORDER BY title ASC;

SELECT * 
FROM party_affiliations
WHERE end_date IS NOT NULL;

SELECT o.legal_name, o.email_address, o.contact_number
FROM officials o
JOIN senators s ON o.official_id = s.official_id;

SELECT o.legal_name, pa.position_title
FROM officials o
LEFT JOIN party_affiliations pa ON o.official_id = pa.official_id;

SELECT * 
FROM parties 
WHERE founding_date = (SELECT MIN(founding_date) FROM parties);

SELECT o.legal_name, o.title
FROM officials o
JOIN ministers m ON o.official_id = m.official_id;

SELECT COUNT(*)
FROM party_affiliations
WHERE party_id = 'some_party_id';

SELECT DISTINCT o.legal_name, o.email_address
FROM officials o
JOIN committee_members cm ON o.official_id = cm.official_id;
